function getFullViewJBrowse2Tracks(chr, geneModelType) {
    let tracks = "";
    if (geneModelType != null) {
        tracks = "Araport11_Loci"; // Araport11 - Gene Locus
        switch (geneModelType) {
            case "protein_coding":
            case "transposable_element_gene":
                tracks += ",Araport11_GeneModels"; // Araport11 - Protein Coding Genes
                break;
            case "uORF":
                tracks += ",Araport11_uORFs"; // Araport11 - Upstream ORFs
                break;
            case "antisense_long_noncoding_rna":
            case "long_noncoding_rna":
            case "antisense_rna":
            case "other_rna":
                tracks = "Araport11_ncRNA"; // Araport11 - Non-Coding RNA
                break;
            case "miRNA_primary_transcript":
            case "small_nucleolar_rna":
            case "pre_trna":
            case "small_nuclear_rna":
            case "ribosomal_rna":
                tracks = "Araport11_smallRNA"; // Araport11 - small RNA Loci
                break;
            case "novel_transcribed_region":
                tracks += ",Araport11_novelTranscRegions"; // Araport11 - Novel Transcribed Regions
                break;
            case "pseudogene":
                tracks += ",Araport11_pseudogenes"; // Araport11 - Pseudogenes
                break;
            default:
                tracks += ",Araport11_GeneModels,Araport11_TEs,Araport11_uORFs,Araport11_novelTranscRegions,Araport11_pseudogenes,Araport11_ncRNA";
                break;
        }
        if (chr && chr !== CHROMOSOME_MITOCHONDRIAL_GENOME) {
            tracks += ",TDNA-Seq"; // TDNA-seq (O'Malley R et al. 2014)
        }
    } else {
        tracks = "Araport11_smallRNA,Araport11_uORFs,Araport11_novelTranscRegions,Araport11_pseudogenes,Araport11_ncRNA,Araport11_GeneModels,Araport11_Loci,TDNA-Seq";
    }
    return tracks;
}

