    <div class="usage-tracker">
      <div class="d-flex align-items-center">
        <div
          class="d-flex gap-2 justify-content-center w-100 align-items-center"
        >
          <h3 class="tracker-title mb-0">Usage Tracker</h3>
          <Tooltip
            :help-text="'Individual subscriptions are now linked to usage. Please refer to our Individual Subscription FAQ in the Quick Links section.'"
            :help-text-aria="'Individual subscriptions are now linked to usage. Please refer to our Individual Subscription FAQ in the Quick Links section.'"
            help-id="usage-tracker"
            label="Usage Tracker"
          />
        </div>
      </div>
      <div v-if="trackerData != null" class="tracker-content">
