<script>
import Api from "@/services/Api";
import Tooltip from "@/components/common/Tooltip.vue";

export default {
  name: "UsageTracker",
  components: {
    Tooltip,
  },
  props: {
    trackerData: {
      type: [Object, null],
      default: null,
    },
    bucketPurchaseLink: {
      type: String,
      default: null,
    },
    partyId: {
      type: String,
      default: null,
    },
    onFetchTrackerData: {
      type: Function,
      required: true,
    },
    isLoading: {
      type: Boolean,
      default: false,
    },
  },
  computed: {
    usagePercentage() {
      if (this.trackerData.remaining_units == this.trackerData.total_units)
        return 100;
      return (
        (this.trackerData.remaining_units / this.trackerData.total_units) * 100
      );
    },
    progressVariant() {
      if (this.usagePercentage > 70) return "success";
      if (this.usagePercentage > 30) return "warning";
      return "danger";
    },
    formattedExpiryDate() {
      return this.formatDisplayDate(this.trackerData.expiry_date);
    },
    formattedFreeExpiryDate() {
      return this.formatDisplayDate(this.trackerData.free_expiry_date);
    },
    formattedAnnualDiscountAppliedDate() {
      return this.formatDisplayDate(this.trackerData.first_annual_purchase_date);
    },
    formattedNextAnnualDiscountDate() {
      if (!this.trackerData.first_annual_purchase_date) return null;
      const appliedDate = new Date(this.trackerData.first_annual_purchase_date);
      if (Number.isNaN(appliedDate.getTime())) return null;
      const nextDate = new Date(appliedDate);
      nextDate.setFullYear(nextDate.getFullYear() + 1);
      return this.formatDisplayDate(nextDate);
    },
    annualDiscountEligibilityMessage() {
      if (!this.trackerData) return null;
      const discountPercentage = Number(this.trackerData.discountPercentage);
      if (Number.isNaN(discountPercentage)) return null;
      if (discountPercentage > 0) {
        return "You are eligible for the annual 300-unit discount ($200).";
      }
      return null;
    },
    activationCodeState() {
      return this.activationCode.length > 0 ? null : false;
    },
  },
  data() {
    return {
      activationCode: "",
      showActivation: false,
      isActivating: false,
      activationError: null,
      activationSuccess: null,
    };
  },
  methods: {
    formatDisplayDate(value) {
      if (!value) return null;
      const dateValue = value instanceof Date ? value : new Date(value);
      if (Number.isNaN(dateValue.getTime())) return null;
      return dateValue.toLocaleDateString("en-US", {
        year: "numeric",
        month: "short",
        day: "numeric",
      });
    },
    async activateSubscription() {
      if (!this.activationCode) {
        this.activationError = "Please enter a valid activation code.";
        return;
      }

      this.isActivating = true;
      this.activationError = null;

      try {
        if (!this.partyId) {
          this.activationError = "Error during activation.";
          this.isActivating = false;
          console.error("partyId is not set properly");
        }
        const response = await Api().post("/subscription/activate/bucket", {
          activationCode: this.activationCode,
          partyId: this.partyId,
        });
        if (response.status && response.status == 200) {
          this.activationSuccess = "Activation Code applied successfully!";
          this.isActivating = false;
          this.activationError = "";
          this.activationCode = "";
          await this.onFetchTrackerData();
        } else {
          throw new Error(response.data.message || "Activation failed");
        }
      } catch (error) {
        // console.log(error);
        if (error.response) {
          this.activationError =
            error.response.data.message ||
            "An error occurred during activation.";
        } else {
          this.activationError =
            error.message ||
            "An error occurred while activating the subscription.";
        }
      } finally {
        this.isActivating = false;
      }
    },
  },
};
</script>

