<script>
import MultiLineSection from "../common/MultiLineSection.vue";
import TableSection from "../common/TableSection.vue";
import LinkWrapper from "../common/LinkWrapper.vue";
import HomologsSection from "./HomologsSection.vue";
import SectionTitle from "./SectionTitle.vue";
import ImageSelector from "./ImageSelector.vue";
import Comments from "./Comments.vue";
import AlphaFoldViewer from "./AlphaFoldViewer.vue";
import Tooltip from "@/components/common/Tooltip.vue";

export default {
  name: "BaseEntry",
  props: ["content", "selectedColIdx", "currIdx"],
  components: {
    MultiLineSection,
    TableSection,
    LinkWrapper,
    HomologsSection,
    SectionTitle,
    ImageSelector,
    Comments,
    AlphaFoldViewer,
    Tooltip,
  },
  data() {
    return {
      selectedImgType: "",
      loading: false,
      errorImg: false,
      entryIsSelected: false,
      sortKey: "",
      showSuccessAlert: false,
      showErrorAlert: false,
    };
  },
  mounted() {
    this.entryIsSelected = false;
    this.$nextTick(() => {
      this.initIframes();
    });
  },
  beforeDestroy() {
    if (this._iframeObservers) {
      this._iframeObservers.forEach((o) => o.disconnect());
    }
  },
  computed: {},
  watch: {
    selectedColIdx: function (newVal, oldVal) {
      if (newVal == this.currIdx) {
        this.entryIsSelected = true;
      } else {
        this.entryIsSelected = false;
      }
    },
  },
  methods: {
    initIframes() {
      const iframes = this.$refs.jbrowse2Iframe;
      if (!iframes) return;
      const iframeList = Array.isArray(iframes) ? iframes : [iframes];
      const listWrapper = this.$el.closest('.list-wrapper');

      iframeList.forEach((iframe) => {
        const url = iframe.getAttribute('data-src');
        if (!url) return;
        const observer = new IntersectionObserver(
          (entries) => {
            entries.forEach((entry) => {
              if (entry.isIntersecting) {
                observer.disconnect();

                // JBrowse2 steals focus on load, which scrolls the WINDOW
                // (not list-wrapper). Lock window scroll while it initializes.
                const preventWindowScroll = () => { window.scrollTo(0, 0); };
                window.addEventListener('scroll', preventWindowScroll);

                iframe.addEventListener('load', () => {
                  setTimeout(() => {
                    iframe.classList.remove('jbrowse2-loading');
                    window.removeEventListener('scroll', preventWindowScroll);
                    window.scrollTo(0, 0);
                  }, 3000);
                }, { once: true });

                iframe.src = url;
              }
            });
          },
          { root: listWrapper, rootMargin: '100px' }
        );
        observer.observe(iframe);
        if (!this._iframeObservers) this._iframeObservers = [];
        this._iframeObservers.push(observer);
      });
    },
    reloadIFrame2() {
      const iframe = Array.isArray(this.$refs.jbrowse2Iframe)
        ? this.$refs.jbrowse2Iframe[0]
        : this.$refs.jbrowse2Iframe;
      let iframeSrc = iframe.getAttribute('data-src');
      iframe.src = "";
      this.$nextTick(() => {
        iframe.src = iframeSrc;
      });
    },
    getStringFields(fields) {
      if (!fields) return [];
      return fields.filter((field) => field.cellType === "string");
    },
    getHtmlRows(fields) {
      if (!fields) return [];
      return fields.filter((field) => field.cellType === "html");
    },
    displayedComments(b) {
      if (b.showRecent) {
        return b.items.slice(-2); // Last two items
      } else {
        return b.items; // All items
      }
    },
    sectionHeaderClass(index) {
      return {
        "mr-2": true,
        "bg-white": index % 2 === 0,
        "bg-light": index % 2 !== 0,
      };
    },
    copyToClipboard(chunks) {
      const sequenceText = chunks
        .map((line) => {
          return line.substring(line.indexOf(" ") + 1).replace(/\s+/g, "");
        })
        .join("");
      navigator.clipboard
        .writeText(sequenceText)
        .then(() => {
          this.showAlert("success");
        })
        .catch((err) => {
          this.showAlert("error");
          console.error("Failed to copy the sequence: ", err);
        });
    },
    showAlert(type) {
      if (type === "success") {
        this.showSuccessAlert = true;
        setTimeout(() => (this.showSuccessAlert = false), 3000); // Hide after 3 seconds
      } else if (type === "error") {
        this.showErrorAlert = true;
        setTimeout(() => (this.showErrorAlert = false), 3000); // Hide after 3 seconds
      }
    },
  },
};
</script>
