import { getAuthProfile, clearCookie } from "@/services/AuthService";
import Api from "@/services/Api";
import Cookies from "js-cookie";

export const authProfile = {
  namespaced: true,
  state: {
    credentialId: null,
    secretKey: null,
    username: null,
    firstname: null,
    lastname: null,
    email: null,
    institution: null,
    userIdentifier: null,
    inLoading: false,
    isTairCurator: null,
    affiliations: null,
    orcidId: null,
    loggedIn: false,
  },
  mutations: {
    // A generic mutation to update state properties
    UPDATE_STATE(state, data) {
      Object.keys(data).forEach((key) => {
        if (state.hasOwnProperty(key)) {
          state[key] = data[key];
        }
      });
    },

    CLEAR_ORCID_ID(state) {
      state.orcidId = null;
    },

    RESET_STATE(state) {
      // Reset each property to its initial state
      state.credentialId = null;
      state.secretKey = null;
      state.username = null;
      state.firstname = null;
      state.lastname = null;
      state.email = null;
      state.institution = null;
      state.userIdentifier = null;
      state.inLoading = false;
      state.affiliations = null;
      state.orcidId = null;
      state.loggedIn = false;
    },

    SET_IN_LOADING(state) {
      state.inLoading = true;
    },

    RESET_IN_LOADING(state) {
      state.inLoading = false;
    },
  },
  actions: {
    async loadAuthProfile({ commit }) {
      // avoid duplicated loading
      if (this.getters.isLoggedIn || this.getters.isAuthProfileLoading)
        return true;
      commit("SET_IN_LOADING");
      const userProfile = await getAuthProfile();
      commit("RESET_IN_LOADING");
      if (userProfile && userProfile.username) {
        // make sure the user profile is not empty
        commit("UPDATE_STATE", userProfile);
        commit("UPDATE_STATE", { loggedIn: true }); // Set loggedIn to true
        return true; // return true when loading the auth profile succeed
      }
      commit("UPDATE_STATE", { loggedIn: false }); // Set loggedIn to false if auth profile fails to load
      return false; // return false when loading the auth profile failed
    },

    clearOrcidId({ commit }) {
      commit("CLEAR_ORCID_ID");
    },

    async invalidate({ commit }) {
      commit("RESET_STATE");
      await clearCookie(); // clear the cookie
      commit("UPDATE_STATE", { loggedIn: false }); // Set loggedIn to false after cookies are cleared
    },

    async getOrcidLoginUrl() {
      try {
        const response = await Api().get("auth/orcidloginlink");
        return response.data.url;
      } catch (e) {
        console.error("Error getting Orcid login URL", e);
      }
    },
  },
  getters: {
    getCredentials: (state) => {
      return {
        credentialId: state.credentialId,
        secretKey: state.secretKey,
      };
    },
    isAuthProfileLoading: (state) => {
      return state.isLoading;
    },
    getIsTairCurator: (state) => {
      return state.isTairCurator;
    },
    isLoggedIn: (state) => {
      // Check if the credentialId and secretKey cookies exist
      const credentialId = Cookies.get("credentialId");
      const secretKey = Cookies.get("secretKey");
      const loggedIn = !!(credentialId && secretKey);
      // Update the Vuex state based on the cookies
      state.loggedIn = loggedIn;
      return loggedIn;
    },
    getLoggedIn: (state) => {
      return state.loggedIn;
    },
    getCommunityId: (state) => {
      return state.userIdentifier;
    },
    getPartyId: (state) => {
      return state.credentialId;
    },
    getFirstName: (state) => {
      return state.firstname;
    },
    getLastName: (state) => {
      return state.lastname;
    },
    getAffiliations: (state) => {
      return state.affiliations;
    },
    getOrcidId: (state) => {
      return state.orcidId;
    },
    getLoginUrl() {
      return (
        process.env.VUE_APP_LOGIN_BASE_URL +
        "/#/contentaccess/login?partnerId=tair&redirect=" +
        process.env.VUE_APP_UI_BASE_URL +
        "/auth/login"
      );
    },
    getForgotUsernameUrl() {
      return (
        process.env.VUE_APP_LOGIN_BASE_URL +
        "/#/contentaccess/login/forgetusername"
      );
    },
  },
};
