                      id="institutionName"
                      v-model="json_data.institutionName"
                      @input="validateEnglishChars('institutionName')"
                      required
                      :aria-describedby="
                        touchedFields.institutionName &&
                        validationErrors.institutionName
                          ? 'institutionNameError'
                          : null
                      "
                      :aria-invalid="
                        touchedFields.institutionName &&
                        validationErrors.institutionName
                          ? 'true'
                          : 'false'
                      "
                    />
                    <div
                      class="text-danger small"
                      v-if="
                        touchedFields.institutionName &&
