                  </div>
                </div>
              </div>

              <!-- Location Information Section -->
              <div class="mb-5">
                <div class="d-flex align-items-center mb-4">
                  <h5 class="mb-0">Location Information</h5>
                </div>

                <div class="row g-4">
                  <div class="col-md-6">
                    <label for="country" class="form-label pt-3 fw-semibold"
                      >Country/Region <span class="text-danger">*</span></label
                    >
                    <select
                      class="form-select form-select-lg bg-light"
