                      v-model="json_data.state"
                      @change="validateState"
                      required
                      :aria-describedby="
                        touchedFields.state && validationErrors.state
                          ? 'stateError'
                          : null
                      "
                      :aria-invalid="
                        touchedFields.state && validationErrors.state
                          ? 'true'
