                        />
                        <label class="form-check-label" for="okEmailDisplay">
                          Display email address on Person detail page
                        </label>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <!-- Alerts -->
              <div
                v-if="successMessage"
