<!-- TopMenu.vue -->
<template>
  <div class="topMenu p-2 d-flex flex-column" style="background-color: #e7e7e2">
    <div
      role="group"
      aria-labelledby="general-actions-label"
      class="d-flex flex-wrap justify-content-start"
    >
      <span id="general-actions-label" class="sr-only"
        >General search actions</span
      >
      <b-button
        v-if="
          category != 'descriptions' &&
          category != 'annotations' &&
          category != 'microarray'
        "
        size="sm"
        class="mr-2"
        @click="handleNewSearch"
        >New Search</b-button
      >
      <b-button
        v-if="category != 'community'"
        size="sm"
        class="mr-2"
        @click="handleDownload('all')"
        >Download All</b-button
      >
      <b-button
        v-if="category != 'community'"
        size="sm"
        class="mr-2"
        @click="handleDownload('checked')"
        >Download Checked</b-button
      >
    </div>

    <div
      role="group"
      aria-labelledby="gene-actions-label"
      class="d-flex flex-wrap justify-content-start mt-2"
      v-if="category == 'genes'"
    >
      <span id="gene-actions-label" class="sr-only">Gene-specific actions</span>
      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handleGoSearch"
        class="mr-2"
        >Get GO Annotations</b-button
      >
      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handlePoSearch"
        class="mr-2"
        >Get PO Annotations</b-button
      >

      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handleGetSequences"
        class="mr-2"
        aria-haspopup="dialog"
        >Get Sequences</b-button
      >
      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handleGetDescriptions"
        class="mr-2"
        >Get Gene Descriptions</b-button
      >
      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handleLocusHistory"
        class="mr-2"
        >Get Locus History</b-button
      >
      <b-button
        v-if="category == 'genes'"
        size="sm"
        @click="handleMicroarray"
        class="mr-2"
        aria-haspopup="dialog"
        >Get Microarray Elements</b-button
      >
    </div>

    <!-- Live region for screen reader announcements -->
    <div class="sr-only" aria-live="polite" aria-atomic="true">
      {{ announcement }}
    </div>

    <!-- <b-button
      v-if="category == 'genes'"
      size="sm"
      @click="$emit('get-checked-sequences')"
      >Get Checked Sequences</b-button
    > -->
  </div>
</template>

<script>
export default {
  props: {
    category: String,
  },
  data() {
    return {
      announcement: "",
    };
  },
  methods: {
    handleNewSearch() {
      this.announcement = "Navigating to new search page.";
      this.$emit("new-search");
    },
    handleDownload(type) {
      this.announcement = `Downloading ${type} results.`;
      this.$emit("download-csv", { category: this.category, type });
    },
    handleGoSearch() {
      this.announcement = "Fetching GO annotations.";
      this.$emit("go-search");
    },
    handlePoSearch() {
      this.announcement = "Fetching PO annotations.";
      this.$emit("po-search");
    },
    handleGetSequences() {
      this.announcement = "Getting sequences.";
      this.$emit("get-sequences");
    },
    handleGetDescriptions() {
      this.announcement = "Getting gene descriptions.";
      this.$emit("get-descriptions");
    },
    handleLocusHistory() {
      this.announcement = "Getting locus history.";
      this.$emit("get-locus-history");
    },
    handleMicroarray() {
      this.announcement = "Getting microarray elements.";
      this.$emit("get-microarray");
    },
  },
};
</script>

