<script>
import LinkWrapper from "@/components/common/LinkWrapper.vue";
import Tooltip from "@/components/common/Tooltip.vue";

export default {
  components: { LinkWrapper, Tooltip },
  props: {
    items: Array,
    fields: Array,
    loading: Boolean,
    error: Boolean,
    showSelect: {
      type: Boolean,
      default: true,
    },
    perPageProp: {
      type: Number,
      default: 25,
    },
  },
  computed: {
    processedFields() {
      return this.fields.map((field) => ({
        ...field,
        sortable: !(
          field.key === "row_num" ||
          field.key === "selected" ||
          field.key === "desc" ||
          field.key === "tv" ||
          field.key === "assoc_data" ||
          field.key === "assoc_data_child" ||
          field.key === "description" ||
          field.key === "stock_number" ||
          field.key === "donor"
        ),
      }));
    },
    paginatedData() {
      let sortedData = [...this.items];
      if (this.sortBy) {
        sortedData.sort((a, b) => {
          let aVal = this.getSortValue(a[this.sortBy]);
          let bVal = this.getSortValue(b[this.sortBy]);

          // Check if values are empty
          const aEmpty = aVal === "" || aVal == null;
          const bEmpty = bVal === "" || bVal == null;

          // If one is empty and the other is not, the empty one goes last
          if (aEmpty && !bEmpty) return 1;
          if (bEmpty && !aEmpty) return -1;

          // If both are empty, consider them equal in terms of ordering
          if (aEmpty && bEmpty) return 0;

          // Normal sorting logic for non-empty values
          if (aVal < bVal) return this.sortDesc ? 1 : -1;
          if (aVal > bVal) return this.sortDesc ? -1 : 1;
          return 0;
        });
      }

      let start = (this.currentPage - 1) * this.perPage;
      let end = start + this.perPage;
      return sortedData.slice(start, end);
    },
  },
  data() {
    return {
      currentPage: 1,
      perPage: this.perPageProp,
      detailsShown: [],
      sortBy: null,
      sortDesc: false,
      paginationAnnouncement: "",
    };
  },
  methods: {
    scrollToTop() {
      window.scrollTo({ top: 0, behavior: "smooth" });
    },
    onSortChanged({ sortBy, sortDesc }) {
      console.log(`Currently sorting by: ${sortBy}, Descending: ${sortDesc}`);
    },
    getSortValue(value) {
      if (value == null) return "";

      if (Array.isArray(value)) {
        return value
          .map((v) => (v && v.name ? v.name.toLowerCase() : ""))
          .join(" ");
      }

      if (typeof value === "object") {
        // Use sortValue if provided (e.g. ISO date strings for proper date sorting)
        if (value.sortValue !== undefined) {
          return value.sortValue;
        }
        return (value.name || value.value || "").toLowerCase();
      }

      if (typeof value === "string") {
        return value.toLowerCase();
      }

      return value;
    },
    updatePaginationAnnouncement() {
      if (this.items.length === 0) {
        this.paginationAnnouncement = "";
        return;
      }
      const start = (this.currentPage - 1) * this.perPage + 1;
      const end = Math.min(this.currentPage * this.perPage, this.items.length);
      this.paginationAnnouncement = `Showing results ${start} to ${end} of ${this.items.length}`;
    },
    toggleDetails(index) {
      const position = this.detailsShown.indexOf(index);
      if (position >= 0) {
        this.detailsShown.splice(position, 1);
      } else {
        this.detailsShown.push(index);
      }
    },
    onRowSelected(items) {
      this.$emit("row-selected", items);
    },
    selectAllRows() {
      this.items.map((i) => (i.selected = true));
    },
    clearSelected() {
      this.items.map((i) => (i.selected = false));
    },
    getAllSequences() {
      let all_locus = this.items.map((g) => g.locus.name);
      this.$router.push({
        path: "/type_sequences",
        name: "BulkSequenceSearch",
        params: { ids: all_locus.join(",") },
      });
    },
    getCheckedSequences() {
      let all_locus = this.items
        .filter((s) => s.selected)
        .map((g) => g.locus.name);
      this.$router.push({
        path: "/type_sequences",
        name: "BulkSequenceSearch",
        params: { ids: all_locus.join(",") },
      });
    },
  },
  watch: {
    currentPage(newVal) {
      this.$emit("update:currentPage", newVal);
      this.updatePaginationAnnouncement();
    },
    perPage() {
      this.currentPage = 1;
      this.updatePaginationAnnouncement();
    },
    paginatedData() {
      this.updatePaginationAnnouncement();
    },
  },
  mounted() {
    this.updatePaginationAnnouncement();
  },
};
</script>

