    border-radius: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    max-height: 180px;
  }

  // Ensure tooltip content is focusable and keyboard navigable
  .overflow-div {
    outline: none;

    &:focus {
      outline: 2px solid #007bff;
      outline-offset: 2px;
    }
  }
}

// Ensure help icons have proper focus styling
.help-icon {
  outline: none;

  &:focus {
    outline: 2px solid #007bff;
    outline-offset: 2px;
    border-radius: 2px;
  }

