        <h3 class="font-weight-bold text-left mr-2">Arabidopsis paralogs</h3>
        <Tooltip
          :help-text="'List of Arabidopsis genes that reside in the same gene family as the query Arabidopsis gene.'"
          help-id="paralogs"
          label="Arabidopsis paralogs"
        />
      </div>
      <div
        v-if="content.paralogs && content.paralogs.length > 0"
        class="d-flex justify-content-right mb-2"
      >
        <b-button
