        />
      </div>

      <div class="d-flex justify-content-right mb-2">
        <b-button
          class="ml-2"
          size="md"
          @click="openNewTab({ type: 'orthologs' })"
          >Download Orthologs</b-button
        >
      </div>
    </div>
    <div class="row">
      <div class="col-sm-6">
        <h4 class="font-weight-bold text-left mb-2">
          {{ content.eudic_ortho.title }}
        </h4>
        <table
