        </h4>
        <table
          class="table-borderless table-layout"
          role="table"
          :aria-label="content.mono_ortho.title + ' orthologs data'"
        >
          <thead class="sr-only">
            <tr>
              <th scope="col">Plant Species</th>
              <th scope="col">Number of Orthologs</th>
            </tr>
