          </tbody>
        </table>

        <h4 class="font-weight-bold text-left mb-2 mt-3">
          {{ content.other_ortho.title }}
        </h4>
        <table
          class="table-borderless table-layout"
          role="table"
          :aria-label="content.other_ortho.title + ' orthologs data'"
        >
          <thead class="sr-only">
            <tr>
