  </div>
</template>
<script>
import Tooltip from "@/components/common/Tooltip.vue";

export default {
  components: {
    Tooltip,
  },
  mounted() {},
  data() {
    return {
      showModal: false,
      triggerElement: null,
    };
  },
  props: ["content", "treeId"],
  methods: {
    openNewTab(obj) {
      if (obj.type) {
        const apiBase = `${process.env.VUE_APP_PHYLOGENES_API}/api/panther`;
        if (obj.type == "orthologs") {
          window.open(`${apiBase}/orthologs-download/${this.treeId}`, "_blank");
        } else if (obj.type == "paralogs") {
          window.open(`${apiBase}/paralogs-download/${this.treeId}`, "_blank");
        }
        // else if (obj.type == "sequences") {
        //   let link = `${process.env.VUE_APP_OLD_TAIR_URL}/servlet/Search?type=gene&search_action=sendToSequenceDLByNames`;
        //   this.meta.agis.forEach((id) => {
        //     link += "&name=" + id;
        //   });
        //   window.open(link, "_blank");
        // }
      }
    },
    showMore() {
      this.triggerElement = this.$refs.showMoreLink;
      this.showModal = true;
      this.$nextTick(() => {
        this.$refs.modal.focus();
      });
    },
    closeModal() {
      this.showModal = false;
      this.$nextTick(() => {
        if (this.triggerElement) {
          this.triggerElement.focus();
        }
      });
    },
  },
};
</script>
