            type: "rows",
            rows: [
              {
                name: "Search Terms",
                value: {
                  type: "mixed",
                  elements: [
                    {
                      type: "select",
                      label: "Publication search type (row 1)",
                      options: [
                        // { text: "Abstract", value: "abstract" },
                        { text: "Author", value: "authors" },
