              },
              {
                name: "",
                value: {
                  type: "mixed",
                  elements: [
                    {
                      type: "select",
                      label: "Publication search type (row 2)",
                      options: [
                        // { text: "Abstract", value: "abstract" },
                        { text: "Author", value: "author" },
                        { text: "Journal/Book Title", value: "pubName" },
                        { text: "Title/Abstract", value: "title_abstract" },
                        { text: "AGI Locus ID", value: "loci" },
                        { text: "PubMed ID", value: "pubmedId" },
                        { text: "DOI", value: "doi" },
                      ],
                      value: "title_abstract",
                      id: "search_type_by_3",
                      size: "medium",
                    },
                    {
                      type: "select",
                      label: "Publication search method (row 2)",
                      options: [
                        { text: "contains", value: "contains" },
                        { text: "starts with", value: "starts_with" },
                        { text: "exactly", value: "exactly" },
                      ],
                      value: "contains",
                      id: "search_method_3",
                      size: "medium",
                    },
                    {
