<template>
  <div>
    <div v-if="!error" class="detail-wrapper">
      <SideNavigation
        :sideColumns="side_cols"
        :selectedIndex="colIdxSelected"
        @section-clicked="sideColClicked"
      />
      <div class="list-wrapper" v-on:scroll.passive="handleScroll">
        <div
          v-if="loading"
          class="d-flex justify-content-center align-items-center"
          style="height: 100%"
        >
          <b-spinner label="Loading..."></b-spinner>
        </div>
        <div
          v-if="json_data"
          class="text-left m-2 font-weight-bold fixed-title"
        >
          <div class="d-flex align-items-center">
            <h3>
              Locus: {{ json_data.name }}
              <span v-if="json_data.repGene && json_data.repGene.symbol">
                ({{ json_data.repGene.symbol }})
              </span>
              <span v-if="json_data.isObsolete" style="color: red"
                >(obsolete)</span
              >
            </h3>
            <PremiumIndicator />
          </div>
        </div>
        <BaseEntry
          v-for="(e, i) in entries"
          :selectedColIdx="colIdxSelected"
          :currIdx="i"
          :key="i"
          :content="e"
          :ref="`entry` + i"
        ></BaseEntry>
      </div>
    </div>
    <div v-else>
      <PageNotFound />
    </div>
  </div>
</template>

<script>
//http://localhost:8082/locus?key=1
import axios from "axios";
import BaseEntry from "@/components/detail/BaseEntry";
import SideNavigation from "@/components/detail/SideNavigation";
import PostsService from "@/services/PostsService";
import PageNotFound from "@/components/common/PageNotFound";
import PremiumIndicator from "@/components/common/PremiumIndicator";

import { getSlimViewUrl2, getFullViewUrl2 } from "@/services/JBrowseService";

import * as annotationsSearch from "@/services/search/annotationsSearch";

export default {
  name: "LocusDetail",
  props: {
    url: String,
  },
  components: {
    BaseEntry,
    SideNavigation,
    PageNotFound,
    PremiumIndicator,
  },
  watch: {},
  data() {
    return {
      loading: false,
      error: false,
      base_url: process.env.VUE_APP_S3_PATH + "locus/",
      phylogenes_api_url: process.env.VUE_APP_PHYLOGENES_API + "/api/panther",
      json_data: null,
      ortho_data: null,
      paralogs_data: null,
      first: {
        title: "Summary",
        name: "ASJKDJDKK",
      },
      side_cols: [
        "Summary",
        "Transcripts",
        "Maps and Mapping Data",
        "Sequences",
        "Protein Data",
        "Expression",
        "Gene Ontology",
        "Homology",
        "Germplasm and Clones",
        "Polymorphisms",
        "Publications",
        "External Links",
      ],
      colIdxSelected: 0,
      entries: [],
      entryPosys: [],
    };
  },
  async mounted() {
    if (this.$route.query.key) {
      this.loadJson(this.$route.query.key);
    }

    if (this.$route.query.name) {
      let name = this.$route.query.name.toUpperCase();
      let response = await PostsService.getLocusIdByName(name);
      let locusId = response.data;
      if (locusId == null) {
        this.error = true;
      } else {
        this.loadJson(locusId);
      }
    }

    // New handling for 'accession' query parameter
    if (this.$route.query.accession) {
      let accession = this.$route.query.accession;
      let response = await PostsService.getLocusIdByAccession(accession);
      let locusId = response.data;
      if (locusId == null) {
        this.error = true;
      } else {
        this.loadJson(locusId);
      }
    }

    // Error handling if none of the parameters are present
    if (
      !this.$route.query.key &&
      !this.$route.query.name &&
      !this.$route.query.accession
    ) {
      this.loading = false;
      this.error = true;
    }
  },
  created() {},
  methods: {
    async loadJson(locusId) {
      try {
        this.loading = true;
        this.json_data = (await this.getLocusDetail(locusId)).data;
      } catch (error) {
        console.error("Error fetching locus details: ", error);
        this.loading = false;
        this.error = true;
        return;
      }
      try {
        this.ortho_data = (await this.getOrthologs()).data;
      } catch (error) {
        // console.error("Error fetching ortholog details: ", error);
        this.ortho_data = null; // Ensure ortho_data is null if there's an error
      }
      try {
        this.paralogs_data = (await this.getParalogs()).data;
      } catch (error) {
        // console.error("Error fetching paralog details: ", error);
        this.paralogs_data = null; // Ensure paralogs_data is null if there's an error
      }
      this.loading = false;
      this.error = false;
      this.processEntries();
      document.title = `Locus: ${this.json_data.name}`;
      this.colIdxSelected = 0;
      this.updateEntryCounts();
      setTimeout(() => {
        this.entries.forEach((e, i) => {
          let entryPagePosY = this.$refs["entry" + i][0].$el.offsetTop;

          this.entryPosys.push(entryPagePosY);
        });
        this.loading = false;
      }, 1000);
    },
    scrollToElement(colIdx) {
      const entryRef = this.$refs["entry" + colIdx];
      const el = entryRef[0].$el;
      if (el) {
        var top = el.offsetTop - 210;
        el.parentElement.scrollTo(0, top);
      }
    },
    handleScroll(e) {
      let scrollTop = e.target.scrollTop + 280;
      let currTopEntry = 0;
      this.entryPosys.forEach((e, i) => {
        if (scrollTop > e) {
          currTopEntry = i;
        }
      });
      this.colIdxSelected = currTopEntry;
    },
    sideColClicked(colIdx) {
      this.scrollToElement(colIdx);
      this.colIdxSelected = colIdx;
    },
    async getLocusDetail(id) {
      return PostsService.getLocusDetail({ key: id });
    },
    async getOrthologs() {
      if (!this.json_data.name) {
        return null;
      }
      return axios({
        method: "get",
        url: `${this.phylogenes_api_url}/orthologs/${this.json_data.name}`,
      });
    },
    async getParalogs() {
      if (!this.json_data.name) {
        return null;
      }
      return axios({
        method: "get",
        url: `${this.phylogenes_api_url}/paralogs/${this.json_data.name}`,
      });
    },
    async getOrthologsDownloadUrl() {
      return `${this.phylogenes_api_url}/orthologs-download/`;
    },
    processEntries() {
      this.side_cols.forEach((title) => {
        let entry = {
          title: title,
          name: title.replace(/\s/g, ""),
        };
        switch (title) {
          default:
            entry.type = "bands";
            entry.bands = [];
            break;
          case "Summary":
            entry.type = "bands";
            entry.bands = this.fillSummary();
            break;
          case "Transcripts":
            entry.type = "bands";
            entry.bands = this.fillTranscripts();
            break;
          case "Maps and Mapping Data":
            entry.type = "bands";
            entry.bands = this.fillMapDetails();
            break;
          case "Sequences":
            entry.type = "bands";
            entry.bands = [this.getSequences()];
            break;
          case "Protein Data":
            entry.type = "bands";
            entry.bands = [this.getProteinData()];
            break;
          case "Expression":
            entry.type = "bands";
            entry.bands = [
              this.getPlantOntology(),
              this.getEFPBrowser(),
              this.getRNAData(),
            ];
            break;
          case "Gene Ontology":
            entry.type = "bands";
            entry.bands = [this.getGeneOntology()];
            break;
          case "Homology":
            entry.type = "bands";
            entry.bands = this.fillHomology();
            let paralogAgis = [];
            if (this.paralogs_data) {
              paralogAgis = this.paralogs_data.map((o) => {
                return o.target_agi;
              });
            }
            entry.meta = { treeId: this.json_data.name, agis: paralogAgis };
            break;
          case "Germplasm and Clones":
            entry.type = "bands";
            entry.bands = [this.getGermplasms(), this.getClones()];
            break;
          case "Polymorphisms":
            entry.type = "bands";
            entry.bands = [this.getPolymorphisms()];
            break;
          case "Publications":
            entry.type = "bands";
            entry.bands = [this.getPublications()];
            break;
          case "External Links":
            entry.type = "bands";
            entry.bands = [this.getExternalLinks()];
            break;
        }

        this.entries.push(entry);
      });
    },
    async updateEntryCounts() {
      //Update Gene Ontology count
      let key = "searchParams_go";
      let searchParams = JSON.parse(localStorage.getItem(key));
      let resp = await annotationsSearch.loadAnnotationsResults(
        searchParams,
        false
      );
      if (!resp.error) {
        let sectionFoundIndex = this.entries.findIndex(
          (e) => e.name === "GeneOntology"
        );
        if (sectionFoundIndex !== -1) {
          this.$set(
            this.entries[sectionFoundIndex].bands[0],
            "count",
            resp.items.length
          );
          this.$set(
            this.entries[sectionFoundIndex].bands[0],
            "entry_name",
            "unique annotations"
          );
        }
      }

      //Update Plant Ontology count
      key = "searchParams_po";
      searchParams = JSON.parse(localStorage.getItem(key));
      resp = await annotationsSearch.loadAnnotationsResults(
        searchParams,
        false
      );
      if (!resp.error) {
        let sectionFoundIndex = this.entries.findIndex(
          (e) => e.name === "Expression"
        );
        if (sectionFoundIndex !== -1) {
          this.$set(
            this.entries[sectionFoundIndex].bands[0],
            "count",
            resp.items.length
          );
          this.$set(
            this.entries[sectionFoundIndex].bands[0],
            "entry_name",
            "unique annotations"
          );
        }
      }
    },

    //Fill Functions
    fillSummary() {
      let geneModelType = this.json_data.repGene.geneModelType;
      // let otherNames = "";
      // // Ensure primary symbol is the first in the list and labeled as (Primary Symbol)
      // if (this.json_data.repGene && this.json_data.repGene.symbol) {
      //   otherNames += `${this.json_data.repGene.symbol} (Primary Symbol)`;
      // }
      // // Add other names, ensuring the primary symbol is not duplicated
      // if (this.json_data.otherNames) {
      //   this.json_data.otherNames.forEach((name) => {
      //     if (name !== this.json_data.repGene.symbol) {
      //       otherNames += `, ${name}`;
      //     }
      //   });
      // }
      let primarySymbol =
        this.json_data.repGene && this.json_data.repGene.symbol
          ? this.json_data.repGene.symbol
          : "";
      let symbolsList = Array.isArray(this.json_data.symbols)
        ? this.json_data.symbols
        : [];

      // Identify primary symbol object
      let upperPrimary = primarySymbol.toUpperCase();
      let primarySymbolObj = symbolsList.find((s) => s.name === upperPrimary);
      let nonPrimarySymbols = symbolsList.filter(
        (s) => s.name !== upperPrimary
      );

      // Process symbols first
      let symbolsTextSet = new Set();

      if (primarySymbolObj) {
        let primaryText = primarySymbolObj.fullName
          ? `${primarySymbolObj.name} (${primarySymbolObj.fullName}) (Primary Symbol)`
          : `${primarySymbolObj.name} (Primary Symbol)`;
        symbolsTextSet.add(primaryText);
      }

      nonPrimarySymbols.forEach((symbolObj) => {
        let symbolText = symbolObj.fullName
          ? `${symbolObj.name} (${symbolObj.fullName})`
          : symbolObj.name;
        symbolsTextSet.add(symbolText);
      });

      let symbolsTextArr = Array.from(symbolsTextSet);
      let symbols = symbolsTextArr.join(", ");

      // Create sets of existing symbol names and fullNames for comparison
      let existingNames = new Set();
      symbolsList.forEach((symbol) => {
        existingNames.add(symbol.name.toUpperCase());
        if (symbol.fullName) {
          existingNames.add(symbol.fullName.toUpperCase());
        }
      });

      // Process other names, excluding any that match symbol names or fullNames
      let otherNamesSet = new Set();
      if (this.json_data.otherNames) {
        this.json_data.otherNames.forEach((name) => {
          // Skip if name is empty or matches any symbol name/fullName (case-insensitive)
          if (name && !existingNames.has(name.toUpperCase())) {
            otherNamesSet.add(name);
          }
        });
      }

      let otherNames = Array.from(otherNamesSet).join("; ");

      let updateHistories = [];
      if (this.json_data.updateHistories) {
        this.json_data.updateHistories.forEach((o) => {
          let log =
            o.tairObjectId +
            " " +
            o.updateType +
            " " +
            o.name +
            " on " +
            o.date;
          updateHistories.push(log);
        });
      }

      let description = this.json_data.repGene.description;
      let tairAccession = "";
      if (this.json_data.tairObjectId) {
        tairAccession = "Locus:" + this.json_data.tairObjectId;
      }

      let bands = [];
      // bands.push({
      //   key: "Locus",
      //   text: this.json_data.name
      // });
      bands.push({
        key: "Gene Model Type",
        text: geneModelType,
      });
      bands.push({
        key: "Symbols",
        text: symbols,
      });
      if (otherNames !== "") {
        bands.push({
          key: "Other Names",
          text: otherNames,
        });
      }
      bands.push({
        key: "Description",
        text: description,
      });
      bands.push(this.getComments());
      bands.push(this.getUpdateHistory());
      bands.push({
        key: "Date last modified",
        text: this.getDateModified(),
      });
      bands.push({
        key: "TAIR Accession",
        text: tairAccession,
      });
      return bands;
    },
    fillTranscripts() {
      let repGeneModel = this.json_data.repGene.name;
      let repGeneModelLink = "/gene?key=" + this.json_data.repGene.geneId;
      let bands = [];
      bands.push({
        key: "Representative Gene Model",
        type: "link",
        text: repGeneModel,
        link: repGeneModelLink,
      });
      if (this.json_data.otherGenes) {
        bands.push(this.getOtherGenes());
      }
      if (this.json_data.transcriptCounts) {
        bands.push(this.getAssociatedTranscripts());
      }

      bands.push(this.getAssociatedTransposons());
      return bands;
    },
    fillMapDetails() {
      let bands = [];
      bands.push(this.getMapDetails());
      if (this.json_data.globalAssignments) {
        bands.push(this.getMapLocations());
      }
      bands.push(this.getMapLinks());
      if (this.json_data.geneticMarkers) {
        bands.push(this.getGeneticMarkers());
      }
      return bands;
    },
    fillHomology() {
      let bands = [];
      bands.push(this.getGeneFamilies());
      bands.push(this.getPantherViewer());
      bands.push(this.getPlantHomologs());
      return bands;
    },

    getDateModified() {
      let date = new Date(this.json_data.dateLastModified);
      return this.dateToYMD(date);
    },
    dateToYMD(date) {
      var d = date.getDate();
      var m = date.getMonth() + 1; //Month from 0 to 11
      var y = date.getFullYear();
      return (
        "" + y + "-" + (m <= 9 ? "0" + m : m) + "-" + (d <= 9 ? "0" + d : d)
      );
    },
    getUpdateHistory() {
      let entry = {
        key: "Update History",
        type: "string_list",
        items: [],
      };
      if (this.json_data.updateHistories) {
        this.json_data.updateHistories.forEach((h) => {
          entry.items.push(
            this.json_data.name +
              " " +
              h.updateType +
              " " +
              h.name +
              " on " +
              h.date
          );
        });
      }
      if (this.json_data.affectedByHistories) {
        this.json_data.affectedByHistories.forEach((h) => {
          let name = h.name ? h.name : "";
          entry.items.push(
            this.json_data.name +
              " " +
              h.updateType +
              " " +
              name +
              " on " +
              h.date
          );
        });
      }
      if (entry.items.length == 0) {
        entry.items.push("No update history available");
      }
      return entry;
    },
    getComments() {
      let entry = {
        key: "Community Comments",
        type: "comment_list",
        showComments: false,
        showRecent: true,
        items: [],
      };
      let items = [];
      if (this.json_data.comments) {
        this.json_data.comments.forEach((c) => {
          let date = new Date(c.dateEntered);
          date = this.getDateModified(date);
          let item = {};
          item.profile = {
            name: c.person.name,
            url: `/person?key=${c.person.communityId}`,
          };
          item.comment = {
            text: c.notepadComment,
            url:
              process.env.VUE_APP_OLD_TAIR_URL +
              "/servlets/TairObject?type=notepad&id=" +
              c.notepadId,
          };
          item.date_posted = date;
          items.push(item);
        });
      }
      entry.items = items;
      if (entry.items.length == 0) {
        entry.items.push({ comment: { text: "No comments found" } });
      }
      return entry;
    },
    getMapDetails() {
      if (this.json_data.jbrowseChromosome == null) {
        let entry = {
          key: "Map Detail Image",
          text: "No map details found",
        };
        return entry;
      }
      let jbrowseChromosome = this.json_data.jbrowseChromosome;
      let spanStartPosition = this.json_data.spanStartPosition;
      let spanEndPosition = this.json_data.spanEndPosition;
      let geneModelType = this.json_data.repGene.geneModelType;
      let jbrowse2Url = getSlimViewUrl2(
        jbrowseChromosome,
        spanStartPosition,
        spanEndPosition,
        geneModelType
      );
      let fullScreenUrl2 = getFullViewUrl2(
        jbrowseChromosome,
        spanStartPosition,
        spanEndPosition,
        geneModelType
      );
      let entry = {
        key: "Map Detail Image",
        type: "iframe",
        name: this.json_data.name,
        jbrowse2Url: jbrowse2Url,
        fullScreenUrl2: fullScreenUrl2,
      };
      return entry;
    },
    //protein data
    getProteinData() {
      let entry = {
        key: "Protein Data",
        type: "table",
        items: [],
        fields: [
          { key: "name_link", label: "Name", cellType: "name_link" },
          { key: "length", label: "Length" },
          { key: "molecular_weight", label: "Molecular Weight" },
          { key: "isoelectric_point", label: "Isoelectric Point" },
          {
            key: "link_list",
            label: "INTERPRO domains",
            cellType: "link_list",
          },
        ],
      };

      if (this.json_data.proteinSequences) {
        this.json_data.proteinSequences.forEach((g) => {
          let item = {};
          let link = "/protein?key=" + g.tairObjectId;
          item.name_link = { name: g.name, link: link };
          item.length = g.length;
          item.molecular_weight = g.molecularWeight;
          item.isoelectric_point = g.isoelectricPoint;
          let links = [];
          if (g.domains) {
            g.domains.forEach((d) => {
              links.push({
                name: d.displayName,
                link:
                  "http://www.ebi.ac.uk/interpro/entry/InterPro/" + d.accession,
              });
            });
          }
          item.link_list = { link_list: links };
          entry.items.push(item);
        });
      }

      if (entry.items.length == 0) {
        entry.type = "";
        entry.text = "No protein data available";
      }
      return entry;
    },

    //Map links
    getMapLinks() {
      let entry = {
        key: "Map Links",
        type: "link_list",
        items: [],
      };
      entry.items.push({
        text: "MapViewer",
        link:
          process.env.VUE_APP_OLD_TAIR_URL +
          "/servlets/mapper?value=" +
          this.json_data.name +
          "&action=search",
      });
      // entry.items.push({
      //   text: "Sequence Viewer",
      //   link:
      //     "https://seqviewer.arabidopsis.org/?action=accession&type=gene&id=" +
      //     this.json_data.repGene.tairObjectId +
      //     "&chr=" +
      //     this.json_data.chromosome,
      // });
      // entry.items.push({
      //   text: "GBrowse",
      //   link:
      //     "https://gbrowse.arabidopsis.org/cgi-bin/gb2/gbrowse/arabidopsis/?name=" +
      //     this.json_data.name,
      // });
      let jbrowseChromosome = this.json_data.jbrowseChromosome;
      let spanStartPosition = this.json_data.spanStartPosition;
      let spanEndPosition = this.json_data.spanEndPosition;
      let geneModelType = this.json_data.repGene.geneModelType;
      let jbrowse2Url = getFullViewUrl2(
        jbrowseChromosome,
        spanStartPosition,
        spanEndPosition,
        geneModelType
      );
      entry.items.push({
        text: "JBrowse",
        link: jbrowse2Url,
      });

      let seqviewerUrl = `${process.env.VUE_APP_SEQVIEWER}/?action=accession&type=gene&id=${this.json_data.repGene.tairObjectId}&chr=${this.json_data.chromosome}`;
      entry.items.push({
        text: "SeqViewer",
        link: seqviewerUrl,
      });
      return entry;
    },
    //sequences
    getSequences() {
      let entry = {
        key: "Sequence",
        type: "link_list",
        items: [],
      };
      let nsq = this.json_data.nucleotideSequences;
      if (nsq && nsq.length > 0) {
        nsq.forEach((n) => {
          entry.items.push({
            text: n.name,
            link: "/sequence?key=" + n.nucleotideSequenceId,
          });
        });
      }

      let psq = this.json_data.proteinSequences;
      if (psq && psq.length > 0) {
        psq.forEach((p) => {
          entry.items.push({
            text: "protein",
            link: "/protein?key=" + p.tairObjectId,
          });
        });
      }
      if (entry.items.length == 0) {
        entry.type = "";
        entry.text = "No sequences available";
      }

      return entry;
    },
    //otherGenes
    getOtherGenes() {
      let entry = {
        key: "Other Gene Models",
        type: "small-table",
        items: [],
        fields: [],
      };
      if (this.json_data.otherGenes) {
        entry.fields.push({
          key: "name_link",
          label: "Gene Name",
          cellType: "name_link",
          helpTxt:
            "This section displays information about the gene model(s) associated to the displayed data (such as the gene associated to an allele, gene models for a locus or genes contained within a clone). Hyperlinks from the gene name will open gene detail pages for the associated genes.",
        });
        // entry.fields.push({
        //   key: "isSplice",
        //   label: "Is Splice Variant",
        //   cellType: "name_link",
        // });
        this.json_data.otherGenes.forEach((g) => {
          let item = {};
          let url = "/gene?key=" + g.geneId;
          item.name_link = { name: g.name, link: url };
          // item.isSplice = { name: g.isSpliceVariant };
          entry.items.push(item);
        });
      }

      return entry;
    },
    //Associated Transcripts
    getAssociatedTranscripts() {
      let entry = {
        key: "Associated Transcripts",
        type: "table",
        items: [],
        fields: [],
      };
      if (this.json_data.transcriptCounts) {
        entry.fields.push({
          key: "type",
          label: "Type",
          cellType: "name_link",
        });
        entry.fields.push({
          key: "Transcript Count",
          label: "Transcript Count",
          cellType: "name_link",
        });
        this.json_data.transcriptCounts.forEach((g) => {
          let item = {};
          item.type = { name: g.transcriptType };
          let locusId = this.json_data.locusId;
          let link =
            process.env.VUE_APP_OLD_TAIR_URL +
