<script>
import HeaderComponent from "@/components/common/HeaderComponent.vue";
import FooterComponent from "@/components/common/FooterComponent.vue";
import { mapGetters } from "vuex";
import Cookies from "js-cookie";
import Api from "@/services/Api";

export default {
  name: "TairHome",
  components: {
    HeaderComponent,
    FooterComponent,
  },
  data() {
    return {
      searchText: null,
      lastSearchText: null,
      searchTypes: ["Gene"],
      selectedSearchType: "Gene",
      searchAlreadyShown: false,
      //   institution: null,
      subscribeStatus: "Subscribed",
      loading: true,
    };
  },
  computed: {
    ...mapGetters("authProfile", ["getLoggedIn"]),
    ...mapGetters("subscriptionStatus", ["institution", "status"]),
  },
  beforeDestroy() {
    // Clear the interval when the component is destroyed
    clearInterval(this.cookieInterval);
  },
  mounted() {
    this.cookieInterval = setInterval(() => {
      this.checkCookies();
    }, 5000);
    // console.log("Is user logged in:", this.getLoggedIn);
    // load auth profile on application mount, but avoid duplicated dispatch
    if (this.$route.path !== "/auth/login") {
      this.$store.dispatch("authProfile/loadAuthProfile");
      this.$store.dispatch("subscriptionStatus/fetchInstitution");
      this.init();
      this.loading = false;
    }
  },
  watch: {
    getLoggedIn(newValue) {
      console.log("loggedIn changed:", newValue); // Logs whenever loggedIn changes
    },
  },
  methods: {
    ...mapGetters("authProfile", ["getLoginUrl"]),
    async init() {},
    goSearch() {
      if (this.searchText && this.searchText !== "") {
        // this.lastSearchText = this.searchText;
        this.$nextTick(() => {
          if (this.$route.path !== "/results") {
            this.searchAlreadyShown = false;
          }
          this.$router.push({
            path: "/results",
            query: {
              mainType: "general",
              searchText: this.searchText,
              category: "genes",
            },
          });
          this.searchText = "";
        });
      }
    },
    async checkCookies() {
      const credentialId = Cookies.get("credentialId");
      const secretKey = Cookies.get("secretKey");

      // If cookies are not present, update the Vuex state to logged out
      if (!credentialId || !secretKey) {
        try {
          // Update the loggedIn state to false
          this.$store.commit("authProfile/UPDATE_STATE", { loggedIn: false });
          // Call the invalidate action to clear session-related data
          await this.$store.dispatch("authProfile/invalidate");
          // Make an API call to logout the user from the backend
          const response = await Api().get("auth/logout");
          // Clear the interval
          clearInterval(this.cookieInterval);
          if (this.$route.path === "/profile") {
            this.$router.push("/");
          }
        } catch (error) {
          console.error("Error while checking cookies and logging out:", error);
        }
      }
    },
  },
};
</script>
