  methods: {
    updateMismatchCheckboxes() {
      if (
        this.form.mismatch !== "0" &&
        !this.form.insertion &&
        !this.form.deletion &&
        !this.form.substitution
      ) {
        this.form.insertion = true;
        this.form.deletion = true;
        this.form.substitution = true;
      }
      if (this.form.mismatch === "0") {
        this.form.insertion = false;
        this.form.deletion = false;
        this.form.substitution = false;
      }
    },
    updateMismatchDropdown() {
      if (
        this.form.mismatch === "0" &&
        (this.form.insertion || this.form.deletion || this.form.substitution)
      ) {
        this.form.mismatch = "1";
      }
      if (
        this.form.mismatch !== "0" &&
        !this.form.insertion &&
        !this.form.deletion &&
        !this.form.substitution
      ) {
        this.form.mismatch = "0";
      }
    },
    handleSubmit() {
      // Form submission logic here
      console.log("Form submitted with data:", this.form);
      const actionUrl = `${process.env.VUE_APP_TOOLS_BASE_URL}/cgi-bin/patmatch/nph-patmatch.pl`;
      const method = "POST";
      const target = "_blank";

      // Map strand values to what the backend expects
      let strandValue;
      switch (this.form.strand) {
        case "Watson":
          strandValue = "Watson";
          break;
        case "Crick":
          strandValue = "Crick";
          break;
        case "both":
        default:
          strandValue = "both strands";
          break;
      }

      const fields = [
        {
          type: "hidden",
          name: "default_db",
          value: this.form.current_db,
        },
        {
          type: "hidden",
          name: "current_db",
          value: this.form.current_db,
        },
        {
          type: "hidden",
          name: "seq_class",
          value: this.form.seq_class,
        },
        {
          type: "hidden",
          name: "pat",
          value: this.form.pat,
        },
        {
          type: "hidden",
          name: "strand",
          value: strandValue,
        },
        {
          type: "hidden",
          name: "maxhits",
          value: this.form.max_hits,
        },
        {
          type: "hidden",
          name: "mismatch",
          value: this.form.mismatch,
        },
        //min_seq_hits
        {
          type: "hidden",
          name: "min_seq_hits",
          value: this.form.min_seq_hits,
        },
        //max_seq_hits
        {
          type: "hidden",
          name: "max_seq_hits",
          value: this.form.max_seq_hits,
        },
        {
          type: "hidden",
          name: "insertion",
          value: this.form.insertion === true ? "on" : "off",
        },
        {
          type: "hidden",
          name: "deletion",
          value: this.form.deletion === true ? "on" : "off",
        },
        {
          type: "hidden",
          name: "substitution",
          value: this.form.substitution === true ? "on" : "off",
        },
      ];
      this.submitForm(actionUrl, method, target, fields);
    },
    submitForm(actionUrl, method, target, fields) {
      console.log("Submitting form with fields:", fields);
      console.log("Selected database:", this.form.current_db);
      console.log("Sequence type:", this.form.seq_class);

      // Create a form element
      const form = document.createElement("form");
      form.method = method;
      form.action = actionUrl;
      form.target = target;

      // Add form fields
      fields.forEach((field) => {
        const input = document.createElement("input");
        input.type = field.type;
        input.name = field.name;
        input.value = field.value;
        form.appendChild(input);
      });

      // Append the form to the body
      document.body.appendChild(form);

      // Submit the form
      form.submit();

      // Remove the form from the body after submission
      document.body.removeChild(form);
    },
    handleReset() {
      this.form = {
        seq_class: "nucleotide",
        pat: "",
        current_db: "",
        max_hits: "75000",
        strand: "both",
        mismatch: "0",
