        max_seq_hits: "100",
      };
      this.onSequenceTypeChange();
    },
    onSequenceTypeChange() {
      console.log("Sequence type changed to:", this.form.seq_class);

      // Set default database option based on sequence type
      if (this.form.seq_class === "peptide") {
        // Find first non-disabled peptide option
        const firstValidOption = this.peptideDatabaseOptions.find(
          (option) => !option.disabled && option.value !== ""
        );
        if (firstValidOption) {
          this.form.current_db = firstValidOption.value;
        }
      } else {
        // Find first non-disabled nucleotide option
        const firstValidOption = this.nucleotideDatabaseOptions.find(
          (option) => !option.disabled && option.value !== ""
        );
        if (firstValidOption) {
          this.form.current_db = firstValidOption.value;
        }
      }
