const requireAccess = async (to, from, next) => {
  // Enable dev bypass for mock views in non-production builds
  const isDevBuild = process.env.NODE_ENV !== "production";

  // Check for any mock* query parameter or localStorage flag
  const hasMockQuery = Object.keys(to.query).some((key) =>
    key.startsWith("mock")
  );
  const hasMockStorage =
    window.localStorage.getItem("mockPersonDetail") === "1" ||
    window.localStorage.getItem("mockProfile") === "1";
  const devBypass = isDevBuild && (hasMockQuery || hasMockStorage);

  if (devBypass) {
    console.log("Access granted (dev mode)");
    next();
    return;
  }

  const userStatus = store.getters.userStatus;
  console.log("Full userStatus:", userStatus);

  if (
    (userStatus.isLoggedIn && userStatus.orcidId) ||
    userStatus.subscriptionStatus === "subscribed"
  ) {
    console.log("Access granted");
    next();
  } else {
    console.log("Access denied");
    next("/access-denied");
  }
};

