    getSymbols() {
      let entry = {
        key: "Symbols",
        type: "table",
        items: [],
        fields: [],
      };
      if (this.json_data.symbols) {
        // Track existing symbols to prevent duplicates
        const seenSymbols = new Set();

        entry.fields.push({
          key: "symbol",
          label: "Symbol",
          cellType: "name_link",
        });
        entry.fields.push({
          key: "fullname",
          label: "Full Name",
          cellType: "name_link",
        });

        // Extract primary symbol for priority
        const primarySymbol = this.json_data.primarySymbol;

        // Add primary symbol first if it exists in the symbols list
        if (primarySymbol) {
          const primaryEntry = this.json_data.symbols.find(
            (s) => s.symbol === primarySymbol
          );
          if (primaryEntry) {
            seenSymbols.add(primaryEntry.symbol);
            entry.items.push({
              symbol: { name: `${primaryEntry.symbol} (Primary Symbol)` },
              fullname: { name: primaryEntry.fullName },
            });
          }
        }

        // Process remaining symbols, skipping duplicates
        this.json_data.symbols.forEach((s) => {
          if (!seenSymbols.has(s.symbol)) {
            seenSymbols.add(s.symbol);
            entry.items.push({
              symbol: { name: s.symbol },
              fullname: { name: s.fullName },
            });
          }
        });
      } else {
        entry.type = "";
        entry.text = "No Symbols available";
        return entry;
      }

      entry.count = entry.items.length;
      return entry;
    },
