      // Retrieve row details from "Search by Name or Phenotype" filter
      const searchFilter = getFilterByName("Search by Name or Phenotype");
      const searchRow = getRowByName(searchFilter, "Search Text");
      const obsoleteRow = getRowByName(searchFilter, "Include obsoleted genes");
      const searchBy =
        searchRow && searchRow.value && Array.isArray(searchRow.value.elements)
          ? (searchRow.value.elements.find((el) => el.id === "search-by") || {})
              .selected
          : undefined;
      const searchType =
        searchRow && searchRow.value && Array.isArray(searchRow.value.elements)
          ? (
              searchRow.value.elements.find((el) => el.id === "search-type") ||
              {}
            ).selected
          : undefined;
      const detailSearchText =
        searchRow && searchRow.value && Array.isArray(searchRow.value.elements)
          ? (searchRow.value.elements.find((el) => el.type === "input") || {})
              .value
          : undefined;
      const include_obsolete =
        obsoleteRow && obsoleteRow.value ? obsoleteRow.value.checked : false;

      //Retrieve row details from "Search by Gene List" filter
      const geneListFilter = getFilterByName("Search by Gene List");
      const geneListRow = getRowByName(geneListFilter, "Gene List Upload");
      const geneListUploadType =
        geneListRow &&
        geneListRow.value &&
        Array.isArray(geneListRow.value.elements)
          ? (
              geneListRow.value.elements.find((el) => el.type === "select") ||
              {}
            ).selected
          : undefined;
      let geneList = this.textareaContent || "";
      geneList = geneList.toLocaleUpperCase();
      geneList = geneList.replace(/\r/g, "");
      geneList = geneList.replace(/\n/g, ";");
      // Remove empty entries caused by trailing semicolons or newlines
      geneList = geneList
        .split(";")
        .map((g) => g.trim())
        .filter((g) => g.length > 0)
        .join(";");

      // Retrieve row details from "Search by Associated Keyword" filter
      const keywordFilter = getFilterByName("Search by Associated Keyword");
      const keywordTermRow = getRowByName(keywordFilter, "Keyword Term");
      const keywordTypeRow = getRowByName(keywordFilter, "Keyword Type");
      const evidenceRow = getRowByName(keywordFilter, "Evidence");
      const keywordTerm =
        keywordTermRow &&
        keywordTermRow.value &&
        Array.isArray(keywordTermRow.value.elements)
          ? (
              keywordTermRow.value.elements.find((el) => el.type === "input") ||
              {}
            ).value
          : undefined;
      const keywordType =
        keywordTypeRow && keywordTypeRow.value
          ? keywordTypeRow.value.selected
          : undefined;
      const evidence =
        evidenceRow && evidenceRow.value
          ? evidenceRow.value.selected
          : undefined;

      // Retrieve row details from "Restrict by Features" filter
      const featuresFilter = getFilterByName("Restrict by Features");
      const geneModelTypeRow = getRowByName(featuresFilter, "Gene Model Type");
      const advancedRow = getRowByName(featuresFilter, "Advanced");
      const geneModelType =
        geneModelTypeRow && geneModelTypeRow.value
          ? geneModelTypeRow.value.selected
          : undefined;
      const advanced =
        advancedRow && advancedRow.value
          ? advancedRow.value.selected
          : undefined;

      // Retrieve row details from "Restrict by Map Locations" filter
      const mapFilter = getFilterByName("Restrict by Map Locations");
      const chromosomeRow = getRowByName(mapFilter, "Chromosome");
      const mapTypeRow = getRowByName(mapFilter, "Map Type");
      const rangeRow = getRowByName(mapFilter, "Range");

      const chromosome =
        chromosomeRow && chromosomeRow.value
          ? chromosomeRow.value.selected
          : undefined;
      const mapType =
        mapTypeRow && mapTypeRow.value ? mapTypeRow.value.selected : undefined;
      const startPos =
        rangeRow && rangeRow.value && Array.isArray(rangeRow.value.elements)
          ? rangeRow.value.elements
              .filter((el) => el.id === "mapRange1")
              .map((el) => el.value)
          : [];
      const endPos =
        rangeRow && rangeRow.value && Array.isArray(rangeRow.value.elements)
          ? rangeRow.value.elements
              .filter((el) => el.id === "mapRange2")
              .map((el) => el.value)
          : [];
      const gaUnit =
        rangeRow && rangeRow.value && Array.isArray(rangeRow.value.elements)
          ? rangeRow.value.elements
              .filter((el) => el.type === "select")
              .map((el) => el.selected)
          : [];

      const search_params = {
        geneListUploadType,
        geneList,
        taxonName,
        searchType,
        searchBy,
        detailSearchText,
        include_obsolete,
        keywordTerm,
        keywordType,
        evidence,
        geneModelType,
        advanced,
        chromosome,
        mapType,
        startPos,
        endPos,
        gaUnit,
        lociMatchCount: 0,
        geneModelCount: 0,
      };

      // Call the function to show results
      // console.log(search_params);
      this.showResults(search_params);
    },
    onReset(event) {
      event.preventDefault();

      // Reset the form data to initial values
      this.textareaContent = "";

      // Reset all form fields to their default values
      this.search_form.filters.forEach((filter) => {
        filter.rows.forEach((row) => {
          if (row.value) {
            if (row.value.type === "checkbox") {
              row.value.checked = false;
            } else if (row.value.type === "select") {
              row.value.selected = row.value.default || null;
            } else if (row.value.type === "multiSelect") {
              row.value.selected =
                row.value.selected.length > 0 ? [row.value.selected[0]] : [];
            } else if (row.value.type === "mixed") {
              row.value.elements.forEach((element) => {
                if (element.type === "input") {
                  element.value = element.default || "";
                } else if (element.type === "select") {
                  element.selected = element.default || null;
                } else if (element.type === "checkbox") {
                  element.checked = false;
                } else if (element.type === "multiInput") {
                  element.value = element.default || "";
                }
              });
            }
          }
        });
      });

      // Clear any file input
      const fileInput = document.getElementById("fileInput");
      if (fileInput) {
        fileInput.value = "";
      }
    },
    showResults(inp_params) {
      let key = "searchParams_" + Date.now();
      localStorage.setItem(key, JSON.stringify(inp_params));
      this.$nextTick(() => {
        this.$router.push({
          path: "/results",
          query: {
            mainType: "detail",
            category: "genes",
            //search_params: JSON.stringify(inp_params),
            key: key,
          },
        });
      });
    },
  },
};
</script>

